import java.io.*;

public class ByteStreamExample {
    public static void main(String[] args) {
        // Writing bytes to a file
        System.out.println("=== Writing bytes ===");
        byte[] data = {65, 66, 67, 68, 69}; // A, B, C, D, E

        try (FileOutputStream fos = new FileOutputStream("bytes.bin")) {
            fos.write(data);
            System.out.println("Bytes written: " + data.length);
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Reading bytes from a file
        System.out.println("=== Reading bytes ===");
        try (FileInputStream fis = new FileInputStream("bytes.bin")) {
            int byteRead;
            System.out.print("Bytes read: ");
            while ((byteRead = fis.read()) != -1) {
                System.out.print(byteRead + " ");
            }
            System.out.println();
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Reading bytes into an array
        System.out.println("=== Reading into array ===");
        try (FileInputStream fis = new FileInputStream("bytes.bin")) {
            byte[] buffer = new byte[10];
            int bytesRead = fis.read(buffer);

            System.out.println("Bytes read: " + bytesRead);
            System.out.print("Data: ");
            for (int i = 0; i < bytesRead; i++) {
                System.out.print((char) buffer[i] + " ");
            }
            System.out.println();
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }

        // Copying a file using byte streams
        System.out.println("=== Copying file ===");
        try (FileInputStream fis = new FileInputStream("source.txt");
             FileOutputStream fos = new FileOutputStream("destination.txt")) {
            byte[] buffer = new byte[1024];
            int bytesRead;
            while ((bytesRead = fis.read(buffer)) != -1) {
                fos.write(buffer, 0, bytesRead);
            }
            System.out.println("File copied successfully!");
        } catch (IOException e) {
            System.out.println("Error copying: " + e.getMessage());
        }
    }
}

phase2.brokenCode:
import java.io.*;

public class Test {
    public static void main(String[] args) {
        FileInputStream fis = null;
        try {
            fis = new FileInputStream("data.bin");
            int data = fis.read();
            System.out.println("Data: " + data);
        } catch (IOException e) {
            System.out.println("Error: " + e.getMessage());
        } finally {
            // Forgot to close fis!
        }
    }
}

phase2.explanation:
You forgot to close the FileInputStream! This causes a resource leak.

Even though the program ends, leaving files open can cause:
• File locks (can't delete/modify file)
• Too many open files (system limit)
• Memory leaks

FIX: Close in finally block:
finally {
    if (fis != null) {
        try {
            fis.close();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

Even better: use try-with-resources!

try (FileInputStream fis = new FileInputStream("data.bin")) {
    // auto-closed!
}

phase3.solution:
import java.io.*;

public class ByteStreamPractice {
    public static void main(String[] args) {
        byte[] data = {10, 20, 30, 40, 50};

        // Write bytes
        try (FileOutputStream fos = new FileOutputStream("numbers.bin")) {
            fos.write(data);
            System.out.println("Wrote " + data.length + " bytes");
        } catch (IOException e) {
            System.out.println("Error writing: " + e.getMessage());
        }

        // Read bytes
        try (FileInputStream fis = new FileInputStream("numbers.bin")) {
            int b;
            System.out.println("Reading bytes:");
            while ((b = fis.read()) != -1) {
                System.out.println("Byte: " + b);
            }
        } catch (IOException e) {
            System.out.println("Error reading: " + e.getMessage());
        }
    }
}
